// Stub: in the real Node-RED runtime this is replaced by 10 coap-request nodes in observe mode, one per CoAP room on the floor (rooms 11-20).
// The concrete URLs are derived at runtime from the floor env var:
//   coap://app:{5683 + floor*100 + room}/f{FLOOR}/r{floor*100+room}/telemetry
// Each notification is forwarded to the mqtt-out node below.
return msg;

// 512-entry LRU keyed by (topic, msg_id, payload_hash). Drops MQTT DUP retransmits so rule chains see each logical message once.
const seen = context.get('seen') || new Map();
const key = (msg.topic || '') + '|' + (msg.messageId || '') + '|' + (msg.payload ? JSON.stringify(msg.payload) : '');
if (seen.has(key)) { return null; }
seen.set(key, Date.now());
if (seen.size > 512) {
    const firstKey = seen.keys().next().value;
    seen.delete(firstKey);
}
context.set('seen', seen);
return msg;

// Port of src/gateways/averaging.py — keeps a 60s window and emits a floor summary on the 60s inject tick.
const windowSeconds = 60;
const samples = context.get('samples') || [];
const now = Date.now() / 1000;
if (msg.payload && msg.payload.temperature !== undefined) {
    samples.push({
        ts: now,
        temp: msg.payload.temperature,
        hum: msg.payload.humidity,
        occ: msg.payload.occupancy ? 1 : 0,
        room: msg.payload.sensor_id
    });
}
while (samples.length && samples[0].ts < now - windowSeconds) samples.shift();
context.set('samples', samples);
return null;

const samples = flow.get('samples_f{{FLOOR}}') || [];
if (!samples.length) return null;
const n = samples.length;
const avgTemp = samples.reduce((s, x) => s + x.temp, 0) / n;
const avgHum = samples.reduce((s, x) => s + x.hum, 0) / n;
const occRatio = samples.reduce((s, x) => s + x.occ, 0) / n;
const rooms = new Set(samples.map(s => s.room)).size;
msg.topic = 'campus/b01/f{{FLOOR}}/summary';
msg.payload = {
    window_seconds: 60,
    samples: n,
    rooms_seen: rooms,
    avg_temperature: +avgTemp.toFixed(2),
    avg_humidity: +avgHum.toFixed(2),
    occupied_ratio: +occRatio.toFixed(3),
    generated_at: Math.floor(Date.now() / 1000)
};
msg.qos = 1;
msg.retain = true;
return msg;

// Topic pattern: campus/b01/fFF/rRRR/cmd
const parts = msg.topic.split('/');
if (parts.length !== 5) return null;
const roomSeg = parts[3];
const roomNum = parseInt(roomSeg.replace('r', ''), 10);
const floorNum = parseInt(parts[2].replace('f', ''), 10);
const localRoom = roomNum - (floorNum * 100);
msg._targetRoom = localRoom;
msg._roomNum = roomNum;
msg._floorNum = floorNum;
if (localRoom <= 10) {
    // MQTT rooms: broker routes directly, gateway only taps for metrics.
    msg._kind = 'mqtt';
    return [msg, null];
}
// CoAP rooms: translate to CON PUT on the actuator resource.
msg._kind = 'coap';
const base = parseInt(global.get('coapBase') || 5683, 10);
msg.url = `coap://${global.get('nodeHost') || 'app'}:${base + floorNum * 100 + localRoom}/f${String(floorNum).padStart(2,'0')}/r${String(roomNum).padStart(3,'0')}/actuators/hvac`;
msg.method = 'PUT';
msg.confirmable = true;
return [null, msg];

// Stub: in the real Node-RED runtime this is a coap-request node.
// Inputs: msg.url, msg.method='PUT', msg.confirmable=true, msg.payload=JSON.
// Output: ACK message with node's CHANGED response payload.
return msg;

msg.topic = `campus/b01/f${String(msg._floorNum).padStart(2,'0')}/r${String(msg._roomNum).padStart(3,'0')}/response`;
msg.qos = 1;
msg.retain = false;
return msg;
